func TestNewValkeyStore(t *testing.T) {
	tests := []struct {
		name    string
		envVars map[string]string
		wantErr bool
		errMsg  string
	}{
		{
			name:    "missing VALKEY_ADDR and REDIS_ADDR",
			envVars: map[string]string{},
			wantErr: true,
			errMsg:  "VALKEY_ADDR or REDIS_ADDR environment variable is not set",
		},
		{
			name: "password required by default",
			envVars: map[string]string{
				"VALKEY_ADDR": "localhost:6379",
			},
			wantErr: true,
			errMsg:  "VALKEY_PASSWORD is required",
		},
		{
			name: "password not required when explicitly disabled",
			envVars: map[string]string{
				"VALKEY_ADDR":              "localhost:6379",
				"VALKEY_PASSWORD_REQUIRED": "false",
			},
			wantErr: true, // Still fails because no Valkey server
		},
		{
			name: "valid configuration",
			envVars: map[string]string{
				"VALKEY_ADDR":     "localhost:6379",
				"VALKEY_PASSWORD": "testpass",
			},
			wantErr: true, // Still fails because no Valkey server
		},
		{
			name: "fallback to REDIS_ADDR",
			envVars: map[string]string{
				"REDIS_ADDR":     "localhost:6379",
				"REDIS_PASSWORD": "testpass",
			},
			wantErr: true, // Still fails because no Valkey server
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			// Clear environment
			for _, key := range []string{"VALKEY_ADDR", "VALKEY_PASSWORD", "VALKEY_PASSWORD_REQUIRED", "REDIS_ADDR", "REDIS_PASSWORD"} {
				_ = os.Unsetenv(key)
			}

			// Set test environment variables
			for key, value := range tt.envVars {
				_ = os.Setenv(key, value)
			}

			// Cleanup
			defer func() {
				for key := range tt.envVars {
					_ = os.Unsetenv(key)
				}
			}()

			store, err := NewValkeyStore()
			if (err != nil) != tt.wantErr {
				t.Errorf("NewValkeyStore() error = %v, wantErr %v", err, tt.wantErr)
				return
			}
			if tt.errMsg != "" && err != nil {
				if err.Error() != tt.errMsg {
					t.Errorf("NewValkeyStore() error message = %v, want %v", err.Error(), tt.errMsg)
				}
			}
			if store != nil {
				_ = store.Close()
			}
		})
	}
}

func TestParseBoolEnv(t *testing.T) {
	tests := []struct {
		name         string
		key          string
		value        string
		defaultValue bool
		want         bool
	}{
		{
			name:         "true value",
			key:          "TEST_BOOL",
			value:        "true",
			defaultValue: false,
			want:         true,
		},
		{
			name:         "false value",
			key:          "TEST_BOOL",
			value:        "false",
			defaultValue: true,
			want:         false,
		},
		{
			name:         "empty uses default true",
			key:          "TEST_BOOL",
			value:        "",
			defaultValue: true,
			want:         true,
		},
		{
			name:         "empty uses default false",
			key:          "TEST_BOOL",
			value:        "",
			defaultValue: false,
			want:         false,
		},
		{
			name:         "invalid value uses default",
			key:          "TEST_BOOL",
			value:        "invalid",
			defaultValue: true,
			want:         true,
		},
		{
			name:         "1 is true",
			key:          "TEST_BOOL",
			value:        "1",
			defaultValue: false,
			want:         true,
		},
		{
			name:         "0 is false",
			key:          "TEST_BOOL",
			value:        "0",
			defaultValue: true,
			want:         false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			// Clear environment
			_ = os.Unsetenv(tt.key)

			// Set value if not empty
			if tt.value != "" {
				_ = os.Setenv(tt.key, tt.value)
				defer os.Unsetenv(tt.key)
			}

			got := parseBoolEnv(tt.key, tt.defaultValue)
			if got != tt.want {
				t.Errorf("parseBoolEnv() = %v, want %v", got, tt.want)
			}
		})
	}
}

