func TestSandboxInfo(t *testing.T) {
	sandbox := &SandboxInfo{
		Kind:             SandboxKind,
		SandboxID:        "sandbox-123",
		SandboxNamespace: "default",
		Name:             "test-sandbox",
		EntryPoints: []SandboxEntryPoint{
			{
				Path:     "/api",
				Protocol: "HTTP",
				Endpoint: "http://localhost:8080",
			},
		},
		SessionID: "session-456",
		CreatedAt: time.Now(),
		ExpiresAt: time.Now().Add(time.Hour),
		Status:    "running",
	}

	if sandbox.Kind != SandboxKind {
		t.Errorf("sandbox.Kind = %v, want %v", sandbox.Kind, SandboxKind)
	}

	if sandbox.SandboxID != "sandbox-123" {
		t.Errorf("sandbox.SandboxID = %v, want %v", sandbox.SandboxID, "sandbox-123")
	}

	if len(sandbox.EntryPoints) != 1 {
		t.Errorf("len(sandbox.EntryPoints) = %v, want %v", len(sandbox.EntryPoints), 1)
	}
}

