func TestCreateSandboxRequest_Validate(t *testing.T) {
	tests := []struct {
		name    string
		req     *CreateSandboxRequest
		wantErr bool
		errType error
	}{
		{
			name: "valid request",
			req: &CreateSandboxRequest{
				Kind:      SandboxKind,
				Name:      "test-sandbox",
				Namespace: "default",
			},
			wantErr: false,
		},
		{
			name: "missing namespace",
			req: &CreateSandboxRequest{
				Kind:      SandboxKind,
				Name:      "test-sandbox",
				Namespace: "",
			},
			wantErr: true,
			errType: ErrNamespaceRequired,
		},
		{
			name: "missing name",
			req: &CreateSandboxRequest{
				Kind:      SandboxKind,
				Name:      "",
				Namespace: "default",
			},
			wantErr: true,
			errType: ErrNameRequired,
		},
		{
			name: "missing both",
			req: &CreateSandboxRequest{
				Kind:      SandboxKind,
				Name:      "",
				Namespace: "",
			},
			wantErr: true,
			// Should return namespace error first
			errType: ErrNamespaceRequired,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := tt.req.Validate()
			if (err != nil) != tt.wantErr {
				t.Errorf("Validate() error = %v, wantErr %v", err, tt.wantErr)
				return
			}

			if tt.errType != nil && err != tt.errType {
				t.Errorf("Validate() error type = %v, want %v", err, tt.errType)
			}
		})
	}
}

